// Nodo: Sigma - Merge Results
// Combina el resultado del Sigma Engine con los datos del evento original
// y prepara el contexto para el Dynamic Scoring y el prompt de IA

const originalEvent = $('Normalize Data (JS)').item.json;
const sigmaResult = $input.item.json;

// Verificar si el Sigma Engine respondió correctamente
const sigmaOk = sigmaResult && typeof sigmaResult.sigma_matched !== 'undefined';

// Valores por defecto si Sigma Engine no respondió
const sigmaData = sigmaOk ? {
  sigma_matched: sigmaResult.sigma_matched,
  sigma_match_count: sigmaResult.match_count || 0,
  sigma_highest_severity: sigmaResult.highest_severity || 'none',
  sigma_risk_score: sigmaResult.sigma_risk_score || 0,
  sigma_mitre_tactics: sigmaResult.mitre_tactics || [],
  sigma_mitre_techniques: sigmaResult.mitre_techniques || [],
  sigma_tags: sigmaResult.sigma_tags || [],
  sigma_context_summary: sigmaResult.sigma_context_summary || 'Motor Sigma no disponible',
  sigma_rules_evaluated: sigmaResult.rules_evaluated || 0,
  sigma_evaluation_ms: sigmaResult.evaluation_time_ms || 0,
  sigma_top_matches: (sigmaResult.matches || []).slice(0, 3).map(m => ({
    title: m.rule_title,
    severity: m.severity,
    techniques: m.mitre_techniques
  }))
} : {
  sigma_matched: false,
  sigma_match_count: 0,
  sigma_highest_severity: 'none',
  sigma_risk_score: 0,
  sigma_mitre_tactics: [],
  sigma_mitre_techniques: [],
  sigma_tags: [],
  sigma_context_summary: 'Motor Sigma no disponible',
  sigma_rules_evaluated: 0,
  sigma_evaluation_ms: 0,
  sigma_top_matches: []
};

// Calcular score bonus por Sigma (para el Dynamic Scoring)
const SIGMA_SEVERITY_BONUS = {
  'none': 0,
  'informational': 2,
  'low': 10,
  'medium': 20,
  'high': 35,
  'critical': 50
};

const sigmaScoreBonus = SIGMA_SEVERITY_BONUS[sigmaData.sigma_highest_severity] || 0;

// Construir el evento enriquecido
const enrichedEvent = {
  ...originalEvent,
  ...sigmaData,
  sigma_score_bonus: sigmaScoreBonus,
  // Flag de prioridad para acelerar análisis críticos
  sigma_priority: sigmaData.sigma_highest_severity === 'critical' || 
                  sigmaData.sigma_mitre_techniques.length > 2
};

return { json: enrichedEvent };

